// src/pages/KhaiBaoCoSo.js
import React, { useState, useCallback, useEffect } from 'react';
import axios from 'axios';
import * as XLSX from 'xlsx'; // Import thư viện xlsx (vẫn dùng để đọc CSV)
import './KhaiBaoCoSo.css'; // Import file CSS
import speciesOptions from '../data/speciesData'; // Import danh sách loài từ file mới (nếu có)
import { jwtDecode } from 'jwt-decode'; // Import jwtDecode

function KhaiBaoCoSo() {
  // Initial form state for resetting
  const initialFormState = {
    // Thông tin cơ sở
    tenCoSo: '', tinhThanhPho: '', xaPhuong: '', diaChiCoSo: '', vido: '', kinhdo: '',
    loaiHinhCoSo: '', ngayThanhLap: '', giayPhepKinhDoanh: '',
    
    // Người đại diện
    tenNguoiDaiDien: '', namSinh: '', soCCCD: '', ngayCapCCCD: '', noiCapCCCD: '',
    soDienThoaiNguoiDaiDien: '', diaChiNguoiDaiDien: '', emailNguoiDaiDien: '',
    
    // Cơ sở gây nuôi
    mucDichNuoi: '', hinhThucNuoi: '', maSoCoSoGayNuoi: '', tongDan: '',
    
    // Cơ sở kinh doanh, chế biến gỗ
    loaiHinhKinhDoanhGo: '', nganhNgheKinhDoanhGo: '', khoiLuong: '',
    
    // Loại cơ sở đăng ký (để phân biệt các trường con)
    loaiCoSoDangKy: '', // Thêm trường này vào state
    
    // Thông tin chung cho cả 2 loại (lâm sản và giấy phép)
    tenLamSan: '', tenKhoaHoc: '', issueDate: '', expiryDate: '',
    trangThai: 'Hoạt động', // Giá trị mặc định
    ghiChu: ''
  };

  const [formData, setFormData] = useState(initialFormState);
  const [message, setMessage] = useState('');
  const [error, setError] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [farms, setFarms] = useState([]); // State để lưu danh sách cơ sở
  const [csvFile, setCsvFile] = useState(null);
  const [excelData, setExcelData] = useState([]); // Dữ liệu từ CSV/Excel
  const [isAdmin, setIsAdmin] = useState(false);
  const [currentPage, setCurrentPage] = useState(1);
  const [totalPages, setTotalPages] = useState(1);
  const [totalFarms, setTotalFarms] = useState(0);
  const [limit, setLimit] = useState(10); // Số lượng mục trên mỗi trang
  const [searchTerm, setSearchTerm] = useState('');
  const [filterType, setFilterType] = useState('');

  const API_BASE_URL = 'http://localhost:10000/api'; // Đảm bảo đúng cổng backend của bạn

  // Kiểm tra vai trò người dùng khi component mount
  useEffect(() => {
    const token = localStorage.getItem('token');
    if (token) {
      try {
        const decodedToken = jwtDecode(token);
        setIsAdmin(decodedToken.role === 'admin');
      } catch (err) {
        console.error('Lỗi giải mã token:', err);
        // Xử lý lỗi giải mã token, ví dụ: xóa token không hợp lệ
        localStorage.removeItem('token');
      }
    }
  }, []);

  // Hàm fetch danh sách cơ sở
  const fetchFarms = useCallback(async () => {
    setIsLoading(true);
    setError('');
    try {
      const token = localStorage.getItem('token');
      if (!token) {
        setError('Bạn cần đăng nhập để xem danh sách cơ sở.');
        setIsLoading(false);
        return;
      }

      const response = await axios.get(`${API_BASE_URL}/farms`, {
        headers: {
          Authorization: `Bearer ${token}`,
        },
        params: {
          page: currentPage,
          limit: limit,
          search: searchTerm,
          loaiCoSoDangKy: filterType,
        },
      });
      // CHỈNH SỬA TẠI ĐÂY: Truy cập vào thuộc tính .docs
      setFarms(response.data.docs); 
      setTotalPages(response.data.totalPages);
      setTotalFarms(response.data.totalDocs);
      setMessage('');
    } catch (err) {
      console.error('Lỗi khi lấy danh sách cơ sở:', err);
      setError('Không thể tải danh sách cơ sở. Vui lòng thử lại.');
      setFarms([]);
    } finally {
      setIsLoading(false);
    }
  }, [currentPage, limit, searchTerm, filterType]);

  // Fetch farms khi component mount hoặc khi currentPage, limit, searchTerm, filterType thay đổi
  useEffect(() => {
    fetchFarms();
  }, [fetchFarms]);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleDateChange = (e) => {
    const { name, value } = e.target;
    // Chuyển đổi giá trị ngày thành đối tượng Date
    setFormData(prev => ({ ...prev, [name]: value ? new Date(value) : '' }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setIsLoading(true);
    setMessage('');
    setError('');

    try {
      const token = localStorage.getItem('token');
      if (!token) {
        setError('Bạn cần đăng nhập để thực hiện thao tác này.');
        setIsLoading(false);
        return;
      }

      const config = {
        headers: {
          'Content-Type': 'application/json',
          Authorization: `Bearer ${token}`,
        },
      };

      await axios.post(`${API_BASE_URL}/farms`, formData, config);
      setMessage('Khai báo cơ sở thành công!');
      setFormData(initialFormState); // Reset form
      fetchFarms(); // Tải lại danh sách sau khi thêm mới
    } catch (err) {
      console.error('Lỗi khi khai báo cơ sở:', err.response ? err.response.data : err.message);
      setError(err.response?.data?.message || 'Có lỗi xảy ra khi khai báo cơ sở. Vui lòng thử lại.');
      if (err.response?.data?.errors) {
        // Hiển thị chi tiết lỗi validation từ backend
        const validationErrors = Object.values(err.response.data.errors).join(', ');
        setError(prev => `${prev} Chi tiết: ${validationErrors}`);
      }
    } finally {
      setIsLoading(false);
    }
  };

  const handleFileUpload = (event) => {
    const file = event.target.files[0];
    if (file) {
      setCsvFile(file);
      const reader = new FileReader();
      reader.onload = (e) => {
        const data = new Uint8Array(e.target.result);
        const workbook = XLSX.read(data, { type: 'array' });
        const sheetName = workbook.SheetNames[0];
        const worksheet = workbook.Sheets[sheetName];
        const json = XLSX.utils.sheet_to_json(worksheet);
        
        // Ánh xạ các trường từ CSV sang các trường trong schema Mongoose
        const processedData = json.map(row => {
          const processedRow = {
            tenCoSo: row['Tên cơ sở'] || '',
            tinhThanhPho: row['Tỉnh/Thành phố'] || '',
            xaPhuong: row['Xã/Phường'] || '',
            diaChiCoSo: row['Địa chỉ cơ sở'] || '',
            vido: row['Vĩ độ'] ? String(row['Vĩ độ']) : '', // Chuyển sang String
            kinhdo: row['Kinh độ'] ? String(row['Kinh độ']) : '', // Chuyển sang String
            loaiHinhCoSo: row['Loại hình cơ sở'] || '',
            ngayThanhLap: row['Ngày thành lập'] ? new Date(row['Ngày thành lập']) : null, // Chuyển sang Date
            giayPhepKinhDoanh: row['Giấy phép kinh doanh'] || '',
            ghiChu: row['Ghi chú'] || '',
            trangThai: row['Trạng thái'] || 'Hoạt động', // Mặc định nếu không có

            tenNguoiDaiDien: row['Tên người đại diện'] || '',
            namSinh: row['Năm sinh'] ? Number(row['Năm sinh']) : null, // Chuyển sang Number
            soCCCD: row['Số CCCD'] || '',
            ngayCapCCCD: row['Ngày cấp CCCD'] ? new Date(row['Ngày cấp CCCD']) : null, // Chuyển sang Date
            noiCapCCCD: row['Nơi cấp CCCD'] || '',
            soDienThoaiNguoiDaiDien: row['Số điện thoại người đại diện'] || '',
            diaChiNguoiDaiDien: row['Địa chỉ người đại diện'] || '',
            emailNguoiDaiDien: row['Email người đại diện'] || '',

            loaiCoSoDangKy: row['Loại cơ sở đăng ký'] || '', // Đảm bảo trường này có trong CSV
            
            // Trường cho Cơ sở gây nuôi
            mucDichNuoi: row['Mục đích nuôi'] || '',
            hinhThucNuoi: row['Hình thức nuôi'] || '',
            maSoCoSoGayNuoi: row['Mã số CS gây nuôi'] || '',
            tongDan: row['Tổng đàn'] ? Number(row['Tổng đàn']) : null, // Chuyển sang Number

            // Trường cho Cơ sở kinh doanh, chế biến gỗ
            loaiHinhKinhDoanhGo: row['Loại hình KD gỗ'] || '',
            nganhNgheKinhDoanhGo: row['Ngành nghề KD gỗ'] || '',
            khoiLuong: row['Khối lượng'] ? Number(row['Khối lượng']) : null, // Chuyển sang Number

            // Trường chung cho giấy phép
            tenLamSan: row['Tên lâm sản'] || '',
            tenKhoaHoc: row['Tên khoa học'] || '',
            issueDate: row['Ngày cấp'] ? new Date(row['Ngày cấp']) : null, // Chuyển sang Date
            expiryDate: row['Ngày hết hạn'] ? new Date(row['Ngày hết hạn']) : null, // Chuyển sang Date
          };
          console.log("Row processed data:", processedRow); // Log dữ liệu đã xử lý
          return processedRow;
        });
        setExcelData(processedData);
        console.log("Dữ liệu đã được xử lý từ CSV (processedData):", processedData);
      };
      reader.readAsArrayBuffer(file);
    }
  };

  const handleBulkSubmit = async () => {
    setIsLoading(true);
    setMessage('');
    setError('');
    console.log("Dữ liệu gửi đi (Bulk Upload):", excelData);

    try {
      const token = localStorage.getItem('token');
      if (!token) {
        setError('Bạn cần đăng nhập để thực hiện thao tác này.');
        setIsLoading(false);
        return;
      }

      const config = {
        headers: {
          'Content-Type': 'application/json',
          Authorization: `Bearer ${token}`,
        },
      };

      const response = await axios.post(`${API_BASE_URL}/farms/bulk`, excelData, config);
      setMessage(`Tải lên hàng loạt thành công! Đã lưu ${response.data.savedCount} cơ sở.`);
      setError(''); // Xóa lỗi nếu có
      setExcelData([]); // Xóa dữ liệu excel đã tải lên
      setCsvFile(null); // Xóa file đã chọn
      fetchFarms(); // Tải lại danh sách sau khi thêm mới
    } catch (err) {
      console.error('Lỗi khi tải lên hàng loạt:', err.response ? err.response.data : err.message);
      let errorMessage = 'Có lỗi xảy ra khi tải lên hàng loạt. Vui lòng kiểm tra lại file CSV và định dạng dữ liệu.';
      if (err.response && err.response.data && err.response.data.errors) {
        // Hiển thị chi tiết lỗi từ backend (ví dụ: lỗi validation cho từng dòng)
        errorMessage += ` Chi tiết lỗi: ${JSON.stringify(err.response.data.errors, null, 2)}`;
      } else if (err.response && err.response.data && err.response.data.message) {
        errorMessage = err.response.data.message;
      }
      setError(errorMessage);
    } finally {
      setIsLoading(false);
    }
  };

  const resetCsvUpload = () => {
    setCsvFile(null);
    setExcelData([]);
    setMessage('');
    setError('');
  };

  const handlePageChange = (newPage) => {
    if (newPage > 0 && newPage <= totalPages) {
      setCurrentPage(newPage);
    }
  };

  const handleLimitChange = (e) => {
    setLimit(parseInt(e.target.value, 10));
    setCurrentPage(1); // Reset về trang 1 khi thay đổi limit
  };

  const handleSearchChange = (e) => {
    setSearchTerm(e.target.value);
    setCurrentPage(1); // Reset về trang 1 khi tìm kiếm
  };

  const handleFilterTypeChange = (e) => {
    setFilterType(e.target.value);
    setCurrentPage(1); // Reset về trang 1 khi lọc
  };


  return (
    <div className="khai-bao-co-so-container">
      <h1>Khai Báo Cơ Sở</h1>

      {message && <div className="success-message">{message}</div>}
      {error && <div className="error-message">{error}</div>}

      <section className="khai-bao-section form-section">
        <h2>Thông tin Khai báo</h2>
        <form onSubmit={handleSubmit} className="khai-bao-form">
          {/* Thông tin cơ sở */}
          <h3>Thông tin cơ sở</h3>
          <div className="form-group">
            <label htmlFor="tenCoSo">Tên cơ sở:</label>
            <input type="text" id="tenCoSo" name="tenCoSo" value={formData.tenCoSo} onChange={handleChange} required />
          </div>
          <div className="form-group">
            <label htmlFor="tinhThanhPho">Tỉnh/Thành phố:</label>
            <input type="text" id="tinhThanhPho" name="tinhThanhPho" value={formData.tinhThanhPho} onChange={handleChange} required />
          </div>
          <div className="form-group">
            <label htmlFor="xaPhuong">Xã/Phường:</label>
            <input type="text" id="xaPhuong" name="xaPhuong" value={formData.xaPhuong} onChange={handleChange} required />
          </div>
          <div className="form-group">
            <label htmlFor="diaChiCoSo">Địa chỉ cơ sở:</label>
            <input type="text" id="diaChiCoSo" name="diaChiCoSo" value={formData.diaChiCoSo} onChange={handleChange} required />
          </div>
          <div className="form-group">
            <label htmlFor="vido">Vĩ độ:</label>
            <input type="text" id="vido" name="vido" value={formData.vido} onChange={handleChange} />
          </div>
          <div className="form-group">
            <label htmlFor="kinhdo">Kinh độ:</label>
            <input type="text" id="kinhdo" name="kinhdo" value={formData.kinhdo} onChange={handleChange} />
          </div>
          <div className="form-group">
            <label htmlFor="loaiHinhCoSo">Loại hình cơ sở:</label>
            <select id="loaiHinhCoSo" name="loaiHinhCoSo" value={formData.loaiHinhCoSo} onChange={handleChange}>
              <option value="">Chọn loại hình</option>
              <option value="Cơ sở gây nuôi">Cơ sở gây nuôi</option>
              <option value="Cơ sở kinh doanh, chế biến gỗ">Cơ sở kinh doanh, chế biến gỗ</option>
              <option value="Cơ sở khác">Cơ sở khác</option>
            </select>
          </div>
          <div className="form-group">
            <label htmlFor="ngayThanhLap">Ngày thành lập:</label>
            <input type="date" id="ngayThanhLap" name="ngayThanhLap" value={formData.ngayThanhLap ? new Date(formData.ngayThanhLap).toISOString().split('T')[0] : ''} onChange={handleDateChange} />
          </div>
          <div className="form-group">
            <label htmlFor="giayPhepKinhDoanh">Giấy phép kinh doanh:</label>
            <input type="text" id="giayPhepKinhDoanh" name="giayPhepKinhDoanh" value={formData.giayPhepKinhDoanh} onChange={handleChange} />
          </div>
          <div className="form-group">
            <label htmlFor="ghiChu">Ghi chú:</label>
            <textarea id="ghiChu" name="ghiChu" value={formData.ghiChu} onChange={handleChange}></textarea>
          </div>
          <div className="form-group">
            <label htmlFor="trangThai">Trạng thái:</label>
            <select id="trangThai" name="trangThai" value={formData.trangThai} onChange={handleChange}>
              <option value="Hoạt động">Hoạt động</option>
              <option value="Tạm dừng">Tạm dừng</option>
              <option value="Đình chỉ">Đình chỉ</option>
            </select>
          </div>

          {/* Người đại diện */}
          <h3>Người đại diện</h3>
          <div className="form-group">
            <label htmlFor="tenNguoiDaiDien">Tên người đại diện:</label>
            <input type="text" id="tenNguoiDaiDien" name="tenNguoiDaiDien" value={formData.tenNguoiDaiDien} onChange={handleChange} />
          </div>
          <div className="form-group">
            <label htmlFor="namSinh">Năm sinh:</label>
            <input type="number" id="namSinh" name="namSinh" value={formData.namSinh} onChange={handleChange} />
          </div>
          <div className="form-group">
            <label htmlFor="soCCCD">Số CCCD:</label>
            <input type="text" id="soCCCD" name="soCCCD" value={formData.soCCCD} onChange={handleChange} />
          </div>
          <div className="form-group">
            <label htmlFor="ngayCapCCCD">Ngày cấp CCCD:</label>
            <input type="date" id="ngayCapCCCD" name="ngayCapCCCD" value={formData.ngayCapCCCD ? new Date(formData.ngayCapCCCD).toISOString().split('T')[0] : ''} onChange={handleDateChange} />
          </div>
          <div className="form-group">
            <label htmlFor="noiCapCCCD">Nơi cấp CCCD:</label>
            <input type="text" id="noiCapCCCD" name="noiCapCCCD" value={formData.noiCapCCCD} onChange={handleChange} />
          </div>
          <div className="form-group">
            <label htmlFor="soDienThoaiNguoiDaiDien">Số điện thoại người đại diện:</label>
            <input type="text" id="soDienThoaiNguoiDaiDien" name="soDienThoaiNguoiDaiDien" value={formData.soDienThoaiNguoiDaiDien} onChange={handleChange} />
          </div>
          <div className="form-group">
            <label htmlFor="diaChiNguoiDaiDien">Địa chỉ người đại diện:</label>
            <input type="text" id="diaChiNguoiDaiDien" name="diaChiNguoiDaiDien" value={formData.diaChiNguoiDaiDien} onChange={handleChange} />
          </div>
          <div className="form-group">
            <label htmlFor="emailNguoiDaiDien">Email người đại diện:</label>
            <input type="email" id="emailNguoiDaiDien" name="emailNguoiDaiDien" value={formData.emailNguoiDaiDien} onChange={handleChange} />
          </div>

          {/* Loại cơ sở đăng ký */}
          <h3>Loại cơ sở đăng ký</h3>
          <div className="form-group">
            <label htmlFor="loaiCoSoDangKy">Chọn loại cơ sở đăng ký:</label>
            <select id="loaiCoSoDangKy" name="loaiCoSoDangKy" value={formData.loaiCoSoDangKy} onChange={handleChange} required>
              <option value="">-- Chọn loại --</option>
              <option value="Đăng ký cơ sở gây nuôi">Đăng ký cơ sở gây nuôi</option>
              <option value="Đăng ký cơ sở kinh doanh, chế biến gỗ">Đăng ký cơ sở kinh doanh, chế biến gỗ</option>
            </select>
          </div>

          {/* Thông tin Cơ sở gây nuôi (hiển thị có điều kiện) */}
          {formData.loaiCoSoDangKy === 'Đăng ký cơ sở gây nuôi' && (
            <>
              <h3>Cơ sở gây nuôi</h3>
              <div className="form-group">
                <label htmlFor="mucDichNuoi">Mục đích nuôi:</label>
                <input type="text" id="mucDichNuoi" name="mucDichNuoi" value={formData.mucDichNuoi} onChange={handleChange} />
              </div>
              <div className="form-group">
                <label htmlFor="hinhThucNuoi">Hình thức nuôi:</label>
                <input type="text" id="hinhThucNuoi" name="hinhThucNuoi" value={formData.hinhThucNuoi} onChange={handleChange} />
              </div>
              <div className="form-group">
                <label htmlFor="maSoCoSoGayNuoi">Mã số cơ sở gây nuôi:</label>
                <input type="text" id="maSoCoSoGayNuoi" name="maSoCoSoGayNuoi" value={formData.maSoCoSoGayNuoi} onChange={handleChange} />
              </div>
              <div className="form-group">
                <label htmlFor="tongDan">Tổng đàn:</label>
                <input type="number" id="tongDan" name="tongDan" value={formData.tongDan} onChange={handleChange} />
              </div>
            </>
          )}

          {/* Thông tin Cơ sở kinh doanh, chế biến gỗ (hiển thị có điều kiện) */}
          {formData.loaiCoSoDangKy === 'Đăng ký cơ sở kinh doanh, chế biến gỗ' && (
            <>
              <h3>Cơ sở kinh doanh, chế biến gỗ</h3>
              <div className="form-group">
                <label htmlFor="loaiHinhKinhDoanhGo">Loại hình kinh doanh gỗ:</label>
                <input type="text" id="loaiHinhKinhDoanhGo" name="loaiHinhKinhDoanhGo" value={formData.loaiHinhKinhDoanhGo} onChange={handleChange} />
              </div>
              <div className="form-group">
                <label htmlFor="nganhNgheKinhDoanhGo">Ngành nghề kinh doanh gỗ:</label>
                <input type="text" id="nganhNgheKinhDoanhGo" name="nganhNgheKinhDoanhGo" value={formData.nganhNgheKinhDoanhGo} onChange={handleChange} />
              </div>
              <div className="form-group">
                <label htmlFor="khoiLuong">Khối lượng:</label>
                <input type="number" id="khoiLuong" name="khoiLuong" value={formData.khoiLuong} onChange={handleChange} />
              </div>
            </>
          )}

          {/* Thông tin chung cho cả 2 loại (lâm sản và giấy phép) */}
          <h3>Thông tin Lâm sản và Giấy phép</h3>
          <div className="form-group">
            <label htmlFor="tenLamSan">Tên lâm sản:</label>
            <input type="text" id="tenLamSan" name="tenLamSan" value={formData.tenLamSan} onChange={handleChange} />
          </div>
          <div className="form-group">
            <label htmlFor="tenKhoaHoc">Tên khoa học:</label>
            <input type="text" id="tenKhoaHoc" name="tenKhoaHoc" value={formData.tenKhoaHoc} onChange={handleChange} />
          </div>
          <div className="form-group">
            <label htmlFor="issueDate">Ngày cấp phép:</label>
            <input type="date" id="issueDate" name="issueDate" value={formData.issueDate ? new Date(formData.issueDate).toISOString().split('T')[0] : ''} onChange={handleDateChange} />
          </div>
          <div className="form-group">
            <label htmlFor="expiryDate">Ngày hết hạn:</label>
            <input type="date" id="expiryDate" name="expiryDate" value={formData.expiryDate ? new Date(formData.expiryDate).toISOString().split('T')[0] : ''} onChange={handleDateChange} />
          </div>

          <button type="submit" className="submit-button" disabled={isLoading}>
            {isLoading ? 'Đang gửi...' : 'Khai báo Cơ sở'}
          </button>
        </form>

        {isAdmin && <hr className="section-divider" />}

        {isAdmin && (
          <section className="khai-bao-section excel-upload-section">
            <div className="file-upload-group">
              <label htmlFor="csvUpload" className="file-upload-label">
                Chọn file CSV (.csv):
              </label>
              <input 
                type="file" 
                id="csvUpload" 
                accept=".csv" 
                onChange={handleFileUpload} 
                className="file-input"
              />
              {csvFile && <span className="file-name">{csvFile.name}</span>}
            </div>
            {excelData.length > 0 && (
              <div className="excel-preview-info">
                <p>Đã đọc được {excelData.length} dòng dữ liệu từ CSV. Vui lòng nhấn "Tải lên hàng loạt" để lưu.</p>
                <button 
                  onClick={handleBulkSubmit} 
                  className="submit-button bulk-upload-button"
                  disabled={isLoading}
                >
                  {isLoading ? 'Đang tải...' : `Tải lên hàng loạt (${excelData.length} cơ sở)`}
                </button>
                <button 
                  onClick={resetCsvUpload} 
                  className="clear-excel-button"
                  disabled={isLoading}
                >
                  Xóa dữ liệu CSV
                </button>
              </div>
            )}
          </section>
        )}
      </section>

      <hr className="section-divider" />

      <section className="khai-bao-section farm-list-section">
        <h2>Danh sách Cơ sở đã Khai báo ({totalFarms} cơ sở)</h2>
        <div className="filters-and-search">
          <input
            type="text"
            placeholder="Tìm kiếm theo tên hoặc địa chỉ..."
            value={searchTerm}
            onChange={handleSearchChange}
            className="search-input"
          />
          <select value={filterType} onChange={handleFilterTypeChange} className="filter-select">
            <option value="">Tất cả loại cơ sở</option>
            <option value="Đăng ký cơ sở gây nuôi">Cơ sở gây nuôi</option>
            <option value="Đăng ký cơ sở kinh doanh, chế biến gỗ">Cơ sở kinh doanh, chế biến gỗ</option>
          </select>
          <select value={limit} onChange={handleLimitChange} className="limit-select">
            <option value="5">5 / trang</option>
            <option value="10">10 / trang</option>
            <option value="25">25 / trang</option>
            <option value="50">50 / trang</option>
          </select>
        </div>

        {isLoading && <p>Đang tải danh sách cơ sở...</p>}
        {!isLoading && farms.length === 0 && <p>Không có cơ sở nào được tìm thấy.</p>}

        {!isLoading && farms.length > 0 && (
          <div className="farm-table-container">
            <table className="farm-table">
              <thead>
                <tr>
                  <th>STT</th>
                  <th>Tên Cơ sở</th>
                  <th>Tỉnh/Thành phố</th>
                  <th>Địa chỉ</th>
                  <th>Loại cơ sở đăng ký</th>
                  <th>Trạng thái</th>
                  <th>Hành động</th>
                </tr>
              </thead>
              <tbody>
                {farms.map((farm, index) => (
                  <tr key={farm._id}>
                    <td>{(currentPage - 1) * limit + index + 1}</td>
                    <td>{farm.tenCoSo}</td>
                    <td>{farm.tinhThanhPho}</td>
                    <td>{farm.diaChiCoSo}</td>
                    <td>{farm.loaiCoSoDangKy}</td>
                    <td>{farm.trangThai}</td>
                    <td>
                      <button className="action-button view-button">Xem</button>
                      {isAdmin && (
                        <>
                          <button className="action-button edit-button">Sửa</button>
                          <button className="action-button delete-button">Xóa</button>
                        </>
                      )}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
            <div className="pagination-controls">
              <button onClick={() => handlePageChange(currentPage - 1)} disabled={currentPage === 1}>
                Trước
              </button>
              <span>Trang {currentPage} / {totalPages}</span>
              <button onClick={() => handlePageChange(currentPage + 1)} disabled={currentPage === totalPages}>
                Sau
              </button>
            </div>
          </div>
        )}
      </section>
    </div>
  );
}

export default KhaiBaoCoSo;
